// Readonly xüsusiyyətlərin sintaksisi
interface Person {
  readonly id: number;
  name: string;
}

let person: Person = { id: 1, name: 'Ali' };
console.log(person); // { id: 1, name: 'Ali' }
person.name = 'Vəli'; // Keçərlidir
// person.id = 2; // Xəta: id yalnız oxuna biləndir

// Readonly xüsusiyyətlər ilə tip aliasları
type Id = number | string;

interface User {
  readonly id: Id;
  name: string;
}

type ReadonlyUser = Readonly<{ id: Id; name: string; email: string }>;

let user: User = { id: 1, name: 'Ali' };
let readonlyUser: ReadonlyUser = { id: 'abc', name: 'Vəli', email: 'veli@example.com' };

console.log(user); // { id: 1, name: 'Ali' }
console.log(readonlyUser); // { id: 'abc', name: 'Vəli', email: 'veli@example.com' }
user.name = 'Məmməd'; // Keçərlidir
// user.id = 2; // Xəta: id yalnız oxuna biləndir
// readonlyUser.name = 'Səməd'; // Xəta: name yalnız oxuna biləndir

// Readonly xüsusiyyətlər siniflərdə
interface Person {
  readonly id: number;
  name: string;
}

class Employee implements Person {
  readonly id: number;
  name: string;

  constructor(id: number, name: string) {
    this.id = id;
    this.name = name;
  }
}

let employee = new Employee(101, 'Ali');
console.log(employee); // Employee { id: 101, name: 'Ali' }
employee.name = 'Vəli'; // Keçərlidir
// employee.id = 102; // Xəta: id yalnız oxuna biləndir

// Readonly və optional xüsusiyyətlər
interface Person {
  readonly id: number;
  name: string;
  age?: number;
}

let person1: Person = { id: 1, name: 'Ali' };
let person2: Person = { id: 2, name: 'Vəli', age: 25 };

console.log(person1); // { id: 1, name: 'Ali' }
console.log(person2); // { id: 2, name: 'Vəli', age: 25 }
// person1.id = 3; // Xəta: id yalnız oxuna biləndir
person1.name = 'Məmməd'; // Keçərlidir

// Funksiyalarda readonly xüsusiyyətlər
interface User {
  readonly id: number;
  name: string;
}

function printUser(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Ali' };
console.log(printUser(user)); // ID: 1, Name: Ali
// user.id = 2; // Xəta: id yalnız oxuna biləndir
user.name = 'Vəli'; // Keçərlidir

// Readonly utility tipi
type User = {
  id: number;
  name: string;
};

let user: Readonly<User> = { id: 1, name: 'Ali' };
console.log(user); // { id: 1, name: 'Ali' }
// user.id = 2; // Xəta: id yalnız oxuna biləndir
// user.name = 'Vəli'; // Xəta: name yalnız oxuna biləndir

// Praktik nümunə
interface Product {
  readonly id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product): string {
  return `Product ${product.id}: ${product.name}, Price: ${product.price}`;
}

let product: Product = { id: 1, name: 'Phone', price: 1000 };
console.log(displayProduct(product)); // Product 1: Phone, Price: 1000
product.name = 'Smartphone'; // Keçərlidir
// product.id = 2; // Xəta: id yalnız oxuna biləndir

// Təhlükəsizlik nümunəsi
interface User {
  readonly id: number;
  name: string;
}

function getUserInfo(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Ali' };
console.log(getUserInfo(user)); // ID: 1, Name: Ali
// user.id = 2; // Xəta: id yalnız oxuna biləndir

// Səhvə yol açan nümunə
let unsafe: any = { id: 1, name: 'Ali' };
console.log(unsafe.id, unsafe.name); // 1, Ali, lakin tip təhlükəsizliyi yoxdur
unsafe.id = 2; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
interface User {
  readonly id: number;
  name: string;
}

let user: User = { id: 1, name: 'Ali' };
console.log(user.id, user.name); // 1, Ali
// user.id = 2; // Xəta: id yalnız oxuna biləndir
user.name = 'Vəli'; // Keçərlidir

// Real layihə ssenarisi
interface UserProfile {
  readonly id: number;
  username: string;
  readonly createdAt: string;
}

function displayProfile(profile: UserProfile): string {
  return `User: ${profile.username}, ID: ${profile.id}, Created: ${profile.createdAt}`;
}

let profile: UserProfile = { id: 1, username: 'ali123', createdAt: '2023-10-01' };
console.log(displayProfile(profile)); // User: ali123, ID: 1, Created: 2023-10-01
profile.username = 'ali456'; // Keçərlidir
// profile.id = 2; // Xəta: id yalnız oxuna biləndir
// profile.createdAt = '2023-11-01'; // Xəta: createdAt yalnız oxuna biləndir

