// Readonly properties with type aliases
type Id = number | string;

interface User {
  readonly id: Id;
  name: string;
}

type ReadonlyUser = Readonly<{ id: Id; name: string; email: string }>;

let user: User = { id: 1, name: 'Alice' };
let readonlyUser: ReadonlyUser = { id: 'abc', name: 'Bob', email: 'bob@example.com' };

console.log(user); // { id: 1, name: 'Alice' }
console.log(readonlyUser); // { id: 'abc', name: 'Bob', email: 'bob@example.com' }
user.name = 'Charlie'; // Valid
// user.id = 2; // Error: id is read-only
// readonlyUser.name = 'Dave'; // Error: name is read-only

// Readonly properties in classes
interface Person {
  readonly id: number;
  name: string;
}

class Employee implements Person {
  readonly id: number;
  name: string;

  constructor(id: number, name: string) {
    this.id = id;
    this.name = name;
  }
}

let employee = new Employee(101, 'Alice');
console.log(employee); // Employee { id: 101, name: 'Alice' }
employee.name = 'Bob'; // Valid
// employee.id = 102; // Error: id is read-only

// Combining readonly and optional properties
interface Person {
  readonly id: number;
  name: string;
  age?: number;
}

let person1: Person = { id: 1, name: 'Alice' };
let person2: Person = { id: 2, name: 'Bob', age: 25 };

console.log(person1); // { id: 1, name: 'Alice' }
console.log(person2); // { id: 2, name: 'Bob', age: 25 }
// person1.id = 3; // Error: id is read-only
person1.name = 'Charlie'; // Valid

// Readonly properties in functions
interface User {
  readonly id: number;
  name: string;
}

function printUser(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Alice' };
console.log(printUser(user)); // ID: 1, Name: Alice
// user.id = 2; // Error: id is read-only
user.name = 'Bob'; // Valid

// Readonly utility type
type User = {
  id: number;
  name: string;
};

let user: Readonly<User> = { id: 1, name: 'Alice' };
console.log(user); // { id: 1, name: 'Alice' }
// user.id = 2; // Error: id is read-only
// user.name = 'Bob'; // Error: name is read-only

// Practical example
interface Product {
  readonly id: number;
  name: string;
  price: number;
}

function displayProduct(product: Product): string {
  return `Product ${product.id}: ${product.name}, Price: ${product.price}`;
}

let product: Product = { id: 1, name: 'Phone', price: 1000 };
console.log(displayProduct(product)); // Product 1: Phone, Price: 1000
product.name = 'Smartphone'; // Valid
