// Security example
interface User {
  readonly id: number;
  name: string;
}

function getUserInfo(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Alice' };
console.log(getUserInfo(user)); // ID: 1, Name: Alice
